148→/// Production executor using `tokio::process::Command`.
149→pub struct TokioExecutor;
150→
151→#[async_trait::async_trait]
152→impl CommandExecutor for TokioExecutor {
153→    async fn execute(&self, cmd: &str, args: &[String]) -> Result<String> {
154→        let output = tokio::process::Command::new(cmd)
155→            .args(args)
156→            .output()
157→            .await
158→            .with_context(|| format!("failed to execute command: {cmd}"))?;
159→
160→        if !output.status.success() {
161→            let stderr = String::from_utf8_lossy(&output.stderr);
162→            anyhow::bail!("command failed (exit {}): {}", output.status, stderr);
163→        }
164→
165→        String::from_utf8(output.stdout).context("command output was not valid UTF-8")
166→    }
